import React, {
  useState,
  createContext,
  useContext,
  useEffect,
  useCallback,
  useRef,
} from 'react';
import { CONSTANTS } from '../constants';
import http, {
  setAccessToken as setHttpAccessToken,
  setOnUnauthorized,
} from '../services/http';

const AppContext = createContext(null);

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (context === null) throw new Error('useAppContext must be used within an AppProvider');
  return context;
};

const DEBUG_DEFAULT =
  (typeof window !== 'undefined' &&
    (window.localStorage.getItem('DEBUG') === '1' ||
      process.env.NODE_ENV !== 'production')) ||
  false;

const MAX_LOGS = 300;
const LOG_UPLOAD_URL = '/meta/client-logs'; // 서버에 수집 API가 있다면 이 경로로 변경하세요.

/** 민감 정보 마스킹 유틸 */
const redact = (value) => {
  if (value == null) return value;
  const str = typeof value === 'string' ? value : JSON.stringify(value);
  // 토큰/패스워드/Authorization 헤더 등 마스킹
  return str
    .replace(/(Bearer\s+)[\w\-.]+/gi, '$1***')
    .replace(/("accessToken"\s*:\s*")([^"]+)(")/gi, '$1***$3')
    .replace(/("refreshToken"\s*:\s*")([^"]+)(")/gi, '$1***$3')
    .replace(/("password"\s*:\s*")([^"]+)(")/gi, '$1***$3')
    .replace(/(password=)[^&\s]+/gi, '$1***');
};

/** JWT payload 디코딩(실패 시 null) */
const decodeJwt = (token) => {
  try {
    const base64 = token.split('.')[1].replace(/-/g, '+').replace(/_/g, '/');
    const json = decodeURIComponent(
      atob(base64)
        .split('')
        .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
        .join(''),
    );
    return JSON.parse(json);
  } catch {
    return null;
  }
};

export const AppProvider = ({ children }) => {
  const [persona, setPersona] = useState('resident');
  const [activeView, setActiveView] = useState('auth');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [toast, setToast] = useState({ message: '', isVisible: false });
  const [accessToken, setAccessToken] = useState(null);

  // --- 디버그 상태/로거 ---
  const [debugEnabled, setDebugEnabled] = useState(!!DEBUG_DEFAULT);
  const [logs, setLogs] = useState([]);
  const toastTimerRef = useRef(null);

  const pushLog = useCallback((level, message, extra) => {
    const entry = {
      ts: new Date().toISOString(),
      level, // 'debug' | 'info' | 'warn' | 'error'
      message,
      extra,
    };
    setLogs((prev) => {
      const next = [...prev, entry];
      if (next.length > MAX_LOGS) next.splice(0, next.length - MAX_LOGS);
      return next;
    });
    if (debugEnabled && typeof window !== 'undefined') {
      // 콘솔 출력(개발 시)
      // eslint-disable-next-line no-console
      (console[level] || console.log)(`[${level.toUpperCase()}] ${message}`, extra ?? '');
    }
    return entry;
  }, [debugEnabled]);

  const clearLogs = useCallback(() => setLogs([]), []);
  const dumpState = useCallback(() => {
    return {
      ts: new Date().toISOString(),
      persona,
      activeView,
      isLoggedIn,
      currentUser,
      hasAccessToken: !!accessToken,
      userAgent: typeof navigator !== 'undefined' ? navigator.userAgent : 'n/a',
    };
  }, [persona, activeView, isLoggedIn, currentUser, accessToken]);

  const downloadLogs = useCallback(() => {
    const payload = {
      meta: dumpState(),
      logs,
    };
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `bolivia-app-logs-${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [logs, dumpState]);

  const uploadLogs = useCallback(async () => {
    try {
      await http.post(LOG_UPLOAD_URL, { meta: dumpState(), logs });
      pushLog('info', 'Client logs uploaded', { count: logs.length });
      showToast('진단 로그를 서버로 전송했습니다.');
    } catch (err) {
      pushLog('error', 'Failed to upload logs', { status: err?.response?.status, err });
      showToast('로그 전송 실패(네트워크 확인).');
    }
  }, [logs, dumpState]); // showToast는 아래에서 정의되지만, 호이스팅 영향없음(런타임 시점에 클로저 됨)

  const showToast = useCallback((message) => {
    if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
    setToast({ message, isVisible: true });
    toastTimerRef.current = setTimeout(() => setToast({ message: '', isVisible: false }), 3000);
  }, []);

  useEffect(() => {
    return () => {
      if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
    };
  }, []);

  const navigateTo = useCallback((viewId) => {
    setActiveView(viewId);
    setIsMenuOpen(false);
    pushLog('debug', 'Navigate', { viewId });
  }, [pushLog]);

  // 최초 마운트 시 토큰 로드 + http 인스턴스에 세팅
  useEffect(() => {
    const saved = window.localStorage.getItem('accessToken');
    if (saved) {
      pushLog('info', 'Restore access token from localStorage');
      setAccessToken(saved);
      setHttpAccessToken(saved);
      const payload = decodeJwt(saved);
      const role = payload?.role || 'RESIDENT';
      const username = payload?.sub || payload?.username;
      setCurrentUser((prev) => prev ?? { username, role, email: payload?.email });
      setPersona(role === 'ADMIN' ? 'admin' : 'resident');
      setIsLoggedIn(true);
      setActiveView('dashboard');
    }
  }, [pushLog]);

  // accessToken 변경 시 영속화/해제
  useEffect(() => {
    if (accessToken) {
      window.localStorage.setItem('accessToken', accessToken);
      setHttpAccessToken(accessToken);
    } else {
      window.localStorage.removeItem('accessToken');
      setHttpAccessToken(null);
    }
  }, [accessToken]);

  // 401 전역 처리(한 번만 등록)
  useEffect(() => {
    setOnUnauthorized(() => {
      pushLog('warn', 'HTTP 401 – auto logout triggered');
      setIsLoggedIn(false);
      setCurrentUser(null);
      setAccessToken(null);
      setActiveView('auth');
      showToast('세션이 만료되었습니다. 다시 로그인 해주세요.');
    });
    pushLog('debug', 'setOnUnauthorized handler registered');
  }, [pushLog, showToast]);

  // 전역 에러/Promise 거부 캡처
  useEffect(() => {
    const onError = (e) => {
      pushLog('error', 'Uncaught error', {
        message: e.message,
        stack: e.error?.stack,
        filename: e.filename,
        lineno: e.lineno,
        colno: e.colno,
      });
    };
    const onRejection = (e) => {
      pushLog('error', 'Unhandled promise rejection', { reason: String(e.reason) });
    };
    window.addEventListener('error', onError);
    window.addEventListener('unhandledrejection', onRejection);
    return () => {
      window.removeEventListener('error', onError);
      window.removeEventListener('unhandledrejection', onRejection);
    };
  }, [pushLog]);

  // 디버그 패널 토글(선택): CTRL+ALT+D
  const [debugPanelOpen, setDebugPanelOpen] = useState(false);
  useEffect(() => {
    const hotkey = (e) => {
      const key = e.key?.toLowerCase();
      if (e.ctrlKey && e.altKey && key === 'd') {
        setDebugPanelOpen((v) => !v);
      }
    };
    window.addEventListener('keydown', hotkey);
    return () => window.removeEventListener('keydown', hotkey);
  }, []);

  // Login with email/username + password
  const login = async (id, password) => {
    pushLog('info', 'Login attempt', { id });
    const t0 = performance.now();
    try {
      const res = await http.post('/auth/login', { id, password });

console.log('Login API Response:', res); 

      const token = res?.data?.accessToken;

      setAccessToken(token);
      setHttpAccessToken(token);

      // 사용자 정보 결정: 우선 서버 응답 → JWT payload
      const apiUser = res?.data?.user;
      const payload = decodeJwt(token);

console.log('API 응답 유저 정보:', apiUser);
console.log('JWT 토큰 payload:', payload);

      const role = apiUser?.role || payload?.auth || 'RESIDENT';   // 수정된 코드

console.log('최종 결정된 역할:', role);

      const username = apiUser?.username || apiUser?.email || payload?.sub || id;
      const email = apiUser?.email || (id.includes('@') ? id : payload?.email);

      const minimalUser = { username, email, role };
      setCurrentUser(minimalUser);
      setPersona(role === 'ADMIN' ? 'admin' : 'resident');
      setIsLoggedIn(true);
      setActiveView('dashboard');


      pushLog('info', 'Login success', {
        ms: Math.round(performance.now() - t0),
        user: { username, role, email },
      });
    } catch (err) {
      pushLog('error', 'Login failed', {
        ms: Math.round(performance.now() - t0),
        status: err?.response?.status,
        data: redact(err?.response?.data),
      });
      showToast('로그인 실패: 아이디/비밀번호 또는 네트워크를 확인하세요.');
      throw err;
    }
  };

  const handleLogout = async () => {
    pushLog('info', 'Logout requested');
    const t0 = performance.now();
    try {
      await http.post('/auth/logout');
      pushLog('debug', 'Logout API called', { ms: Math.round(performance.now() - t0) });
    } catch (err) {
      // 무시하지만 로그 남김
      pushLog('warn', 'Logout API failed', {
        status: err?.response?.status,
        data: redact(err?.response?.data),
      });
    }
    setIsLoggedIn(false);
    setCurrentUser(null);
    setAccessToken(null);
    setActiveView('auth');
    showToast('Se ha cerrado la sesión.');
  };

  // Axios-backed wrapper with fetch-like interface + 디버그 로깅
  const fetchWithAuth = async (url, options = {}) => {
    const method = (options.method || 'GET').toUpperCase();
    const headers = options.headers || {};
    const data = options.body ? options.body : undefined;

    const t0 = performance.now();
    pushLog('debug', 'HTTP request', {
      url,
      method,
      headers: redact(headers),
      bodyPreview: data ? redact(typeof data === 'string' ? data : JSON.stringify(data)) : undefined,
    });

    try {
      const res = await http.request({ url, method, headers, data });
      const ms = Math.round(performance.now() - t0);
      pushLog('info', 'HTTP response', {
        url,
        status: res.status,
        ms,
        size: (() => {
          try {
            const s = JSON.stringify(res.data);
            return s ? s.length : undefined;
          } catch {
            return undefined;
          }
        })(),
      });
      return { ok: true, status: res.status, json: async () => res.data };
    } catch (err) {
      const resp = err?.response;
      const ms = Math.round(performance.now() - t0);
      if (!resp) {
        pushLog('error', 'HTTP network error', { url, ms, err: String(err) });
        throw err;
      }
      pushLog('warn', 'HTTP error response', {
        url,
        status: resp.status,
        ms,
        data: redact(resp.data),
      });
      return { ok: false, status: resp.status, json: async () => resp.data };
    }
  };

  const value = {
    // 기존 값
    persona,
    activeView,
    isLoggedIn,
    currentUser,
    setCurrentUser,
    isMenuOpen,
    contentData: CONSTANTS.CONTENT_DATA,
    toast,
    navigateTo,
    login,
    handleLogout,
    showToast,
    setIsMenuOpen,
    fetchWithAuth,
    accessToken,

    // 디버그/진단
    debugEnabled,
    setDebugEnabled,
    logs,
    clearLogs,
    downloadLogs,
    uploadLogs,
    dumpState,
    debugPanelOpen,
    setDebugPanelOpen,
  };

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
};

import React, { useEffect, useRef, useState } from 'react';
import Chart from 'chart.js/auto';
import { useAppContext } from '../../contexts/AppContext';
import Modal from '../../components/common/Modal';
import { useTranslation } from 'react-i18next';

const AdminDashboard = () => {
  const { navigateTo, fetchWithAuth } = useAppContext();
  const { t } = useTranslation();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [kpi, setKpi] = useState({ outstanding: 0, incomes: 0, expenses: 0 });

  const lineRef = useRef(null);
  const pieRef = useRef(null);
  const lineChart = useRef(null);
  const pieChart = useRef(null);

  const ym = (d) => `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;

  useEffect(() => {
    const load = async () => {
      try {
        const to = new Date();
        const from = new Date(to.getFullYear(), to.getMonth() - 5, 1);
        const qs = `?from=${ym(from)}&to=${ym(to)}`;

        const resIn = await fetchWithAuth('/admin/reports/incomes');
        const incomes = resIn.ok ? await resIn.json() : [];

        const resEx = await fetchWithAuth('/admin/reports/expenses');
        const expenses = resEx.ok ? await resEx.json() : [];

        const resDel = await fetchWithAuth(`/admin/reports/delinquency${qs}`);
        const delin = resDel.ok ? await resDel.json() : [];

        const incomesSum = incomes.reduce((s, r) => s + Number(r.total || 0), 0);
        const expensesSum = expenses.reduce((s, r) => s + Number(r.total || 0), 0);
        const outstandingSum = delin.reduce((s, r) => s + Number(r.outstanding || 0), 0);
        setKpi({ incomes: incomesSum, expenses: expensesSum, outstanding: outstandingSum });

        const monthsSet = new Set([...incomes.map((x) => x.month), ...expenses.map((x) => x.month)]);
        const months = Array.from(monthsSet).sort();
        const imap = incomes.reduce((m, x) => ((m[x.month] = Number(x.total || 0)), m), {});
        const exByMonth = expenses.reduce((m, x) => {
          const key = x.month; m[key] = (m[key] || 0) + Number(x.total || 0); return m;
        }, {});
        const incomeSeries = months.map((m) => imap[m] || 0);
        const expenseSeries = months.map((m) => exByMonth[m] || 0);

        if (lineChart.current) lineChart.current.destroy();
        lineChart.current = new Chart(lineRef.current, {
          type: 'line',
          data: {
            labels: months,
            datasets: [
              { label: t('finance.incomes'), data: incomeSeries, borderColor: '#16a34a', backgroundColor: 'rgba(22,163,74,0.2)', tension: 0.3 },
              { label: t('finance.expenses'), data: expenseSeries, borderColor: '#dc2626', backgroundColor: 'rgba(220,38,38,0.2)', tension: 0.3 }
            ]
          },
          options: { responsive: true, plugins: { legend: { position: 'bottom' } } }
        });

        const lastMonth = months[months.length - 1];
        const expLast = expenses.filter((x) => x.month === lastMonth);
        const labels = expLast.map((x) => x.itemName || x.item_name || 'Item');
        const values = expLast.map((x) => Number(x.total || 0));
        const colors = ['#0ea5e9','#22c55e','#ef4444','#a855f7','#f59e0b','#06b6d4','#84cc16'];
        if (pieChart.current) pieChart.current.destroy();
        pieChart.current = new Chart(pieRef.current, {
          type: 'pie',
          data: { labels, datasets: [{ data: values, backgroundColor: colors }] },
          options: { responsive: true, plugins: { legend: { position: 'bottom' } } }
        });
      } catch (e) { /* ignore */ }
    };
    load();
    return () => { if (lineChart.current) lineChart.current.destroy(); if (pieChart.current) pieChart.current.destroy(); };
  }, [fetchWithAuth]);

  return (
    <>
      <div className="bg-white rounded-lg shadow-lg p-6 md:p-8">
        <h2 className="text-2xl font-bold mb-4 text-sky-700">{t('nav.dashboard')}</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-center">
          <div onClick={() => navigateTo('resident_management')} className="bg-gray-50 p-4 rounded-lg shadow cursor-pointer hover:bg-gray-100 transition-colors">
            <p className="text-2xl text-gray-500">{t('finance.outstanding')}</p>
            <p className="text-3xl font-bold text-red-600">{kpi.outstanding.toLocaleString()}원</p>
          </div>
          <div className="bg-gray-50 p-4 rounded-lg shadow">
            <p className="text-2xl text-gray-500">{t('finance.incomes')}</p>
            <p className="text-3xl font-bold text-green-600">{kpi.incomes.toLocaleString()}원</p>
          </div>
          <div className="bg-gray-50 p-4 rounded-lg shadow">
            <p className="text-2xl text-gray-500">{t('finance.expenses')}</p>
            <p className="text-3xl font-bold text-blue-600">{kpi.expenses.toLocaleString()}원</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-8">
          <div className="bg-white p-4 rounded-lg border">
            <h4 className="font-semibold mb-2">{t('finance.trend')}</h4>
            <canvas ref={lineRef} height="160" />
          </div>
          <div className="bg-white p-4 rounded-lg border">
            <h4 className="font-semibold mb-2">{t('finance.expenseShareRecent')}</h4>
            <canvas ref={pieRef} height="160" />
          </div>
        </div>

        <div className="mt-8">
          <button onClick={() => setIsModalOpen(true)} className="w-full p-3 rounded bg-gradient-to-r from-fuchsia-600 to-violet-500 text-white font-bold">{t('communication.aiSummaryButton')}</button>
        </div>
      </div>
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={t('communication.summaryModalTitle')}>
        <div className="text-sm text-gray-700">{t('communication.aiDisabled')}</div>
      </Modal>
    </>
  );
};

export default AdminDashboard;

import React, { useEffect, useMemo, useRef, useState } from 'react';
import Chart from 'chart.js/auto';
import { useAppContext } from '../../contexts/AppContext';
import Loader from '../../components/common/Loader';
import ErrorAlert from '../../components/common/ErrorAlert';
import { useTranslation } from 'react-i18next';

const parseYm = (ym) => {
  if (!ym) return 0;
  const [y, m] = ym.split('-').map((v) => parseInt(v, 10));
  return (y || 0) * 100 + (m || 0);
};

const toYm = (date) => `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;

const FinanceScreen = () => {
  const { fetchWithAuth } = useAppContext();
  const { t } = useTranslation();
  const [incomes, setIncomes] = useState([]);
  const [expenses, setExpenses] = useState([]);
  const [delinquency, setDelinquency] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Filters
  const today = new Date();
  const defaultFrom = new Date(today.getFullYear(), today.getMonth() - 2, 1);
  const [fromYm, setFromYm] = useState(toYm(defaultFrom));
  const [toYmVal, setToYmVal] = useState(toYm(today));
  const [category, setCategory] = useState('ALL');

  // Charts
  const lineRef = useRef(null);
  const pieRef = useRef(null);
  const lineChart = useRef(null);
  const pieChart = useRef(null);

  // Load all datasets on mount
  useEffect(() => {
    const load = async () => {
      try {
        setLoading(true);
        setError('');
        const [resIn, resEx] = await Promise.all([
          fetchWithAuth('/admin/reports/incomes'),
          fetchWithAuth('/admin/reports/expenses'),
        ]);
        const incomeData = resIn.ok ? await resIn.json() : [];
        const expenseData = resEx.ok ? await resEx.json() : [];
        setIncomes(incomeData);
        setExpenses(expenseData);

        // initial delinquency for default range
        const resDel = await fetchWithAuth(`/admin/reports/delinquency?from=${fromYm}&to=${toYmVal}`);
        const delData = resDel.ok ? await resDel.json() : [];
        setDelinquency(delData);
      } catch (e) {
        setError(t('finance.errors.loadFailed'));
      } finally {
        setLoading(false);
      }
    };
    load();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Unique categories from expenses
  const categories = useMemo(() => {
    const set = new Set();
    expenses.forEach((x) => set.add(x.itemName || x.item_name || ''));
    return ['ALL', ...Array.from(set).filter(Boolean).sort()];
  }, [expenses]);

  // Apply filters (client-side for incomes/expenses; server-side for delinquency)
  const applyFilters = async () => {
    try {
      setLoading(true);
      setError('');
      const resDel = await fetchWithAuth(`/admin/reports/delinquency?from=${fromYm}&to=${toYmVal}`);
      const delData = resDel.ok ? await resDel.json() : [];
      setDelinquency(delData);
    } catch (e) {
      setError(t('finance.errors.applyFilterFailed'));
    } finally {
      setLoading(false);
    }
  };

  const withinRange = (ym) => {
    const n = parseYm(ym);
    return n >= parseYm(fromYm) && n <= parseYm(toYmVal);
  };

  const filteredIncomes = useMemo(() => incomes.filter((x) => withinRange(x.month)), [incomes, fromYm, toYmVal]);
  const filteredExpenses = useMemo(() => {
    return expenses.filter((x) => withinRange(x.month)).filter((x) => {
      const cat = x.itemName || x.item_name || '';
      return category === 'ALL' || cat === category;
    });
  }, [expenses, fromYm, toYmVal, category]);

  const sum = (arr, key) => arr.reduce((s, r) => s + Number(r[key] || 0), 0);
  const incomesSum = sum(filteredIncomes, 'total');
  const expensesSum = sum(filteredExpenses, 'total');
  const outstandingSum = delinquency.reduce((s, r) => s + Number(r.outstanding || 0), 0);

  // Build charts when data changes
  useEffect(() => {
    try {
      // Line chart: incomes vs expenses by month within range
      const monthsSet = new Set([
        ...filteredIncomes.map((x) => x.month),
        ...filteredExpenses.map((x) => x.month),
      ]);
      const months = Array.from(monthsSet).sort();
      const imap = filteredIncomes.reduce((m, x) => ((m[x.month] = Number(x.total || 0)), m), {});
      const exByMonth = filteredExpenses.reduce((m, x) => {
        const k = x.month; m[k] = (m[k] || 0) + Number(x.total || 0); return m;
      }, {});
      const incomeSeries = months.map((m) => imap[m] || 0);
      const expenseSeries = months.map((m) => exByMonth[m] || 0);
      if (lineChart.current) lineChart.current.destroy();
      if (lineRef.current) {
        lineChart.current = new Chart(lineRef.current, {
          type: 'line',
          data: { labels: months, datasets: [
            { label: t('finance.incomes'), data: incomeSeries, borderColor: '#16a34a', backgroundColor: 'rgba(22,163,74,0.2)', tension: 0.3 },
            { label: t('finance.expenses'), data: expenseSeries, borderColor: '#dc2626', backgroundColor: 'rgba(220,38,38,0.2)', tension: 0.3 }
          ] },
          options: { responsive: true, plugins: { legend: { position: 'bottom' } } }
        });
      }

      // Pie chart: expenses by item in the latest month within range
      const lastMonth = months[months.length - 1];
      const expLast = filteredExpenses.filter((x) => x.month === lastMonth);
      const labels = expLast.map((x) => x.itemName || x.item_name || 'Item');
      const values = expLast.map((x) => Number(x.total || 0));
      const colors = ['#0ea5e9','#22c55e','#ef4444','#a855f7','#f59e0b','#06b6d4','#84cc16'];
      if (pieChart.current) pieChart.current.destroy();
      if (pieRef.current) {
        pieChart.current = new Chart(pieRef.current, {
          type: 'pie',
          data: { labels, datasets: [{ data: values, backgroundColor: colors }] },
          options: { responsive: true, plugins: { legend: { position: 'bottom' } } }
        });
      }
    } catch (e) { /* ignore */ }
    return () => {
      if (lineChart.current) lineChart.current.destroy();
      if (pieChart.current) pieChart.current.destroy();
    };
  }, [filteredIncomes, filteredExpenses]);

  const downloadCsv = () => {
    const lines = [];
    lines.push('"Incomes"');
    lines.push('month,total');
    filteredIncomes.forEach(r => lines.push(`${r.month},${Number(r.total || 0)}`));
    lines.push('');
    lines.push('"Expenses"');
    lines.push('month,item,total');
    filteredExpenses.forEach(r => lines.push(`${r.month},"${(r.itemName || r.item_name || '').replace(/"/g,'""')}",${Number(r.total || 0)}`));
    lines.push('');
    lines.push('"Delinquency"');
    lines.push('month,billed,paid,outstanding,rate');
    delinquency.forEach(r => lines.push(`${r.month},${Number(r.billed || 0)},${Number(r.paid || 0)},${Number(r.outstanding || 0)},${Number(r.rate || 0)}`));
    const blob = new Blob([lines.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `finance-report_${fromYm}_${toYmVal}.csv`;
    a.click();
    URL.revokeObjectURL(a.href);
  };

  const downloadPdf = () => {
    // Simple print-to-PDF via new window
    const w = window.open('', 'printWin');
    if (!w) return;
    const style = '<style>table{width:100%;border-collapse:collapse}th,td{border:1px solid #ddd;padding:6px;text-align:right}th{text-align:left;background:#f3f4f6}</style>';
    const kpiHtml = `<h2>Finance Report (${fromYm} ~ ${toYmVal})</h2>
      <p>Total Incomes: ${incomesSum.toLocaleString()}</p>
      <p>Total Expenses: ${expensesSum.toLocaleString()}</p>
      <p>Outstanding: ${outstandingSum.toLocaleString()}</p>`;
    const incRows = filteredIncomes.map(r => `<tr><td>${r.month}</td><td>${Number(r.total||0).toLocaleString()}</td></tr>`).join('');
    const exRows = filteredExpenses.map(r => `<tr><td>${r.month}</td><td style="text-align:left">${r.itemName||r.item_name||''}</td><td>${Number(r.total||0).toLocaleString()}</td></tr>`).join('');
    const delRows = delinquency.map(r => `<tr><td>${r.month}</td><td>${Number(r.billed||0).toLocaleString()}</td><td>${Number(r.paid||0).toLocaleString()}</td><td>${Number(r.outstanding||0).toLocaleString()}</td><td>${(Number(r.rate||0)*100).toFixed(1)}%</td></tr>`).join('');
    const html = `<!doctype html><html><head><meta charset="utf-8">${style}</head><body>${kpiHtml}
      <h3>Incomes (Monthly)</h3><table><thead><tr><th>Month</th><th>Total</th></tr></thead><tbody>${incRows}</tbody></table>
      <h3>Expenses (Month/Item)</h3><table><thead><tr><th>Month</th><th>Item</th><th>Total</th></tr></thead><tbody>${exRows}</tbody></table>
      <h3>Delinquency</h3><table><thead><tr><th>Month</th><th>Billed</th><th>Paid</th><th>Outstanding</th><th>Rate</th></tr></thead><tbody>${delRows}</tbody></table>
      <script>window.onload=function(){window.print();window.close();}</script>
    </body></html>`;
    w.document.open();
    w.document.write(html);
    w.document.close();
  };

  if (loading) return <Loader message={t('common.loading')} />;
  if (error) return <div className="p-6"><ErrorAlert message={error} /></div>;

  return (
    <div className="bg-white rounded-lg shadow-lg p-6 md:p-8">
      <h2 className="text-2xl font-bold mb-4 text-sky-700">{t('nav.finance')}</h2>

      {/* Filters */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <div>
          <label className="block text-sm text-gray-600 mb-1">{t('finance.filters.from')}</label>
          <input type="month" value={fromYm} onChange={(e) => setFromYm(e.target.value)} className="w-full p-2 border rounded" />
        </div>
        <div>
          <label className="block text-sm text-gray-600 mb-1">{t('finance.filters.to')}</label>
          <input type="month" value={toYmVal} onChange={(e) => setToYmVal(e.target.value)} className="w-full p-2 border rounded" />
        </div>
        <div>
          <label className="block text-sm text-gray-600 mb-1">{t('finance.filters.category')}</label>
          <select value={category} onChange={(e) => setCategory(e.target.value)} className="w-full p-2 border rounded bg-white">
            {categories.map((c) => (
              <option key={c} value={c}>{c || t('common.na')}</option>
            ))}
          </select>
        </div>
        <div className="flex items-end">
          <button onClick={applyFilters} className="w-full p-2 rounded bg-teal-600 text-white hover:bg-teal-700">{t('common.apply')}</button>
        </div>
      </div>

      {/* KPI */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-center mb-8">
        <div className="bg-gray-50 p-4 rounded-lg shadow">
          <p className="text-2xl text-gray-500">{t('finance.incomes')}</p>
          <p className="text-3xl font-bold text-green-600">{incomesSum.toLocaleString()}원</p>
        </div>
        <div className="bg-gray-50 p-4 rounded-lg shadow">
          <p className="text-2xl text-gray-500">{t('finance.expenses')}</p>
          <p className="text-3xl font-bold text-blue-600">{expensesSum.toLocaleString()}원</p>
        </div>
        <div className="bg-gray-50 p-4 rounded-lg shadow">
          <p className="text-2xl text-gray-500">{t('finance.outstanding')}</p>
          <p className="text-3xl font-bold text-red-600">{outstandingSum.toLocaleString()}원</p>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        <div className="bg-white p-4 rounded border">
          <h4 className="font-semibold mb-2">{t('finance.trend')}</h4>
          <canvas ref={lineRef} height="160" />
        </div>
        <div className="bg-white p-4 rounded border">
          <h4 className="font-semibold mb-2">{t('finance.expenseShareRecent')}</h4>
          <canvas ref={pieRef} height="160" />
        </div>
      </div>

      {/* Tables */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-4 rounded border">
          <h4 className="font-semibold mb-2">{t('finance.sections.incomesMonthly')}</h4>
          <table className="w-full text-sm">
            <thead className="bg-gray-100"><tr><th className="p-2 text-left">{t('finance.table.month')}</th><th className="p-2 text-right">{t('finance.table.total')}</th></tr></thead>
            <tbody>
              {filteredIncomes.map((r, idx) => (
                <tr key={idx} className="border-b">
                  <td className="p-2">{r.month}</td>
                  <td className="p-2 text-right">{Number(r.total || 0).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="bg-white p-4 rounded border">
          <h4 className="font-semibold mb-2">{t('finance.sections.expensesMonthItem')}</h4>
          <table className="w-full text-sm">
            <thead className="bg-gray-100"><tr><th className="p-2 text-left">{t('finance.table.month')}</th><th className="p-2 text-left">{t('finance.table.item')}</th><th className="p-2 text-right">{t('finance.table.total')}</th></tr></thead>
            <tbody>
              {filteredExpenses.map((r, idx) => (
                <tr key={idx} className="border-b">
                  <td className="p-2">{r.month}</td>
                  <td className="p-2">{r.itemName || r.item_name}</td>
                  <td className="p-2 text-right">{Number(r.total || 0).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-white p-4 rounded border mt-6">
        <h4 className="font-semibold mb-2">{t('finance.sections.delinquencyRange')}</h4>
        <table className="w-full text-sm">
          <thead className="bg-gray-100"><tr><th className="p-2 text-left">{t('finance.table.month')}</th><th className="p-2 text-right">{t('finance.table.billed')}</th><th className="p-2 text-right">{t('finance.table.paid')}</th><th className="p-2 text-right">{t('finance.table.outstanding')}</th><th className="p-2 text-right">{t('finance.table.rate')}</th></tr></thead>
          <tbody>
            {delinquency.map((r, idx) => (
              <tr key={idx} className="border-b">
                <td className="p-2">{r.month}</td>
                <td className="p-2 text-right">{Number(r.billed || 0).toLocaleString()}</td>
                <td className="p-2 text-right">{Number(r.paid || 0).toLocaleString()}</td>
                <td className="p-2 text-right">{Number(r.outstanding || 0).toLocaleString()}</td>
                <td className="p-2 text-right">{(Number(r.rate || 0) * 100).toFixed(1)}%</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Downloads */}
      <div className="mt-6 flex gap-3">
        <button onClick={downloadCsv} className="px-4 py-2 rounded bg-gray-700 text-white hover:bg-gray-800">{t('finance.actions.downloadCsv')}</button>
        <button onClick={downloadPdf} className="px-4 py-2 rounded bg-sky-600 text-white hover:bg-sky-700">{t('finance.actions.downloadPdf')}</button>
      </div>
    </div>
  );
};

export default FinanceScreen;

import React, { useState, useEffect } from 'react';
import { useAppContext } from '../../contexts/AppContext';
import { useTranslation } from 'react-i18next';

const ReservationApprovalScreen = () => {
    const { showToast, fetchWithAuth } = useAppContext();
    const { t } = useTranslation();
    const [reservations, setReservations] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState(null);

    const fetchReservations = async () => {
        setIsLoading(true);
        setError(null);
        try {
            const response = await fetchWithAuth('/admin/reservations');
            if (!response.ok) {
                throw new Error(t('reservations.errors.loadFailed'));
            }
            const data = await response.json();
            setReservations(data);
        } catch (err) {
            setError(err.message);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchReservations();
    }, []);

    const handleStatusChange = async (id, newStatus) => {
        try {
            const response = await fetchWithAuth(`/admin/reservations/${id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status: newStatus })
            });

            if (!response.ok) {
                throw new Error(t('reservations.errors.updateFailed'));
            }
            
            // Actualiza el estado en la UI inmediatamente para una mejor experiencia de usuario
            setReservations(reservations.map(r => r.id === id ? { ...r, status: newStatus } : r));
            showToast(t('reservations.success.marked', { status: newStatus.toLowerCase() }));

        } catch (err) {
            showToast(t('common.errorWithMessage', { message: err.message }));
        }
    };

    const statusColor = { 'Aprobada': 'text-green-800 bg-green-100', 'Pendiente': 'text-yellow-800 bg-yellow-100', 'Rechazada': 'text-red-800 bg-red-100', 'Cancelada': 'text-gray-800 bg-gray-100' };

    if (isLoading) return <div className="p-6 text-center">{t('reservations.loading')}</div>;
    if (error) return <div className="p-6 text-center text-red-500">{t('common.errorWithMessage', { message: error })}</div>;

    return (
        <div className="bg-white rounded-lg shadow-lg p-6 md:p-8 text-gray-800">
            <h2 className="text-2xl font-bold text-sky-700 mb-6">{t('reservations.title')}</h2>
            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="bg-gray-100">
                        <tr>
                            <th className="p-3">{t('reservations.table.requester')}</th>
                            <th className="p-3">{t('reservations.table.facility')}</th>
                            <th className="p-3">{t('reservations.table.date')}</th>
                            <th className="p-3">{t('reservations.table.status')}</th>
                            <th className="p-3 text-center">{t('reservations.table.actions')}</th>
                        </tr>
                    </thead>
                    <tbody>
                        {reservations.map(res => (
                            <tr key={res.id} className="border-b hover:bg-gray-50">
                                <td className="p-3 font-semibold">{res.user_name}</td>
                                <td className="p-3">{res.facility_name}</td>
                                <td className="p-3">{new Date(res.start_time).toLocaleString()}</td>
                                <td className="p-3">
                                    <span className={`px-2 py-1 text-xs rounded-full font-medium ${statusColor[res.status]}`}>
                                        {res.status}
                                    </span>
                                </td>
                                <td className="p-3 text-center">
                                    {res.status === 'Pendiente' && (
                                        <div className="flex gap-2 justify-center">
                                            <button onClick={() => handleStatusChange(res.id, 'Aprobada')} className="text-xs bg-blue-500 text-white px-2 py-1 rounded hover:bg-blue-600">{t('reservations.actions.approve')}</button>
                                            <button onClick={() => handleStatusChange(res.id, 'Rechazada')} className="text-xs bg-red-500 text-white px-2 py-1 rounded hover:bg-red-600">{t('reservations.actions.reject')}</button>
                                        </div>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default ReservationApprovalScreen;

import React, { useState, useEffect } from 'react';
import { useAppContext } from '../../contexts/AppContext'; // La ruta puede variar
import { useTranslation } from 'react-i18next';

const ResidentManagementScreen = () => {
    // --- 수정된 부분 1: useAppContext에서 fetchWithAuth 가져오기 ---
    const { showToast, fetchWithAuth } = useAppContext();
    const { t } = useTranslation();
    const [bills, setBills] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState(null);

    const [isFormVisible, setIsFormVisible] = useState(false);
    const [editingBill, setEditingBill] = useState(null);
    const [formData, setFormData] = useState({ household_name: '', bill_month: '', total_amount: '', status: 'Pendiente', due_date: '' });


    const fetchBills = async () => {
        setIsLoading(true);
        setError(null);
        try {
            // --- 수정된 부분 2: fetch를 fetchWithAuth로 변경 ---
            const response = await fetchWithAuth('/admin/bills');
            if (!response.ok) throw new Error(t('bills.errors.loadFailed'));
            const data = await response.json();
            setBills(data);
        } catch (err) {
            setError(err.message);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchBills();
    }, []);

    const handleInputChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });
    
    const handleEdit = (bill) => {
        setEditingBill(bill);
        const formattedBill = { ...bill, due_date: new Date(bill.due_date).toISOString().split('T')[0] };
        setFormData(formattedBill);
        setIsFormVisible(true);
    };

    const handleDelete = async (billId) => {
        // 참고: window.confirm 대신 Modal 컴포넌트를 사용하면 더 나은 UX를 제공할 수 있습니다.
        if (window.confirm(t('bills.confirmDelete'))) {
            try {
                // --- 수정된 부분 3: fetch를 fetchWithAuth로 변경 ---
                const response = await fetchWithAuth(`/api/admin/bills/${billId}`, { method: 'DELETE' });
                if (!response.ok) throw new Error(t('bills.errors.deleteFailed'));
                showToast(t('bills.success.deleted'));
                fetchBills(); // Recargar la lista
            } catch (err) {
                showToast(t('common.errorWithMessage', { message: err.message }));
            }
        }
    };

    const handleAddNew = () => {
        setEditingBill(null);
        setFormData({ household_name: '', bill_month: '2025-09', total_amount: '', status: 'Pendiente', due_date: '' });
        setIsFormVisible(true);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        const url = editingBill ? `/admin/bills/${editingBill.id}` : '/api/admin/bills';
        const method = editingBill ? 'PUT' : 'POST';

        try {
            // --- 수정된 부분 4: fetch를 fetchWithAuth로 변경 ---
            const response = await fetchWithAuth(url, {
                method: method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData)
            });
            if (!response.ok) {
                const errData = await response.json();
                throw new Error(errData.message || t('bills.errors.operationFailed'));
            }
            showToast(editingBill ? t('bills.success.updated') : t('bills.success.created'));
            setIsFormVisible(false);
            fetchBills(); // Recargar la lista
        } catch (err) {
            showToast(t('common.errorWithMessage', { message: err.message }));
        }
    };

    const statusColor = { 'Pendiente': 'text-red-500', 'Pagado': 'text-green-500', 'Pago Parcial': 'text-yellow-500' };

    if (isLoading) return <div className="p-6 text-center">{t('common.loading')}</div>;
    if (error) return <div className="p-6 text-center text-red-500">{t('common.errorWithMessage', { message: error })}</div>;

    return (
        <div className="bg-white rounded-lg shadow-lg p-6 md:p-8 text-gray-800">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-sky-700">{t('bills.title')}</h2>
                {!isFormVisible && <button onClick={handleAddNew} className="bg-sky-600 text-white px-4 py-2 rounded-lg hover:bg-sky-700">{t('bills.actions.new')}</button>}
            </div>

            {isFormVisible && (
                <form onSubmit={handleSubmit} className="bg-gray-50 p-4 rounded-lg mb-6 space-y-3 border">
                    <h3 className="text-lg font-semibold">{editingBill ? t('bills.form.editTitle') : t('bills.form.newTitle')}</h3>
                    <input name="household_name" value={formData.household_name} onChange={handleInputChange} placeholder="Unidad (Ej: 101동 1502호)" className="w-full p-2 border rounded" required disabled={!!editingBill} />
